import { requireAuth } from '@/lib/supabase/server';
import { createClient } from '@/lib/supabase/server';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { DollarSign, TrendingUp, TrendingDown, Wallet, CreditCard, PiggyBank } from 'lucide-react';

export default async function AdminFinancialPage() {
    const profile = await requireAuth();
    const supabase = await createClient();

    // Fetch financial data
    const { data: transactions } = await supabase
        .from('financial_transactions')
        .select('amount, type, category_id, transaction_date, status');

    const { data: accounts } = await supabase
        .from('financial_accounts')
        .select('id, name, balance');

    const transactionsData = transactions || [];
    const accountsData = accounts || [];

    // Calculate totals
    const totalIncome = transactionsData
        .filter((t: any) => (t.type === 'income' || t.type === 'entrada') && t.status !== 'cancelada')
        .reduce((sum: number, t: any) => sum + (t.amount || 0), 0);

    const totalExpenses = transactionsData
        .filter((t: any) => (t.type === 'expense' || t.type === 'saida') && t.status !== 'cancelada')
        .reduce((sum: number, t: any) => sum + (t.amount || 0), 0);

    const netBalance = totalIncome - totalExpenses;

    const totalAccountBalance = accountsData.reduce((sum: number, a: any) =>
        sum + (a.balance || 0), 0
    );

    // This month
    const thisMonth = new Date();
    thisMonth.setDate(1);
    const thisMonthStr = thisMonth.toISOString().split('T')[0];

    const incomeThisMonth = transactionsData
        .filter((t: any) =>
            (t.type === 'income' || t.type === 'entrada') &&
            t.transaction_date >= thisMonthStr
        )
        .reduce((sum: number, t: any) => sum + (t.amount || 0), 0);

    const expensesThisMonth = transactionsData
        .filter((t: any) =>
            (t.type === 'expense' || t.type === 'saida') &&
            t.transaction_date >= thisMonthStr
        )
        .reduce((sum: number, t: any) => sum + (t.amount || 0), 0);

    const formatCurrency = (value: number) =>
        new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);

    return (
        <div className="space-y-6">
            <div>
                <h1 className="text-2xl font-bold">Visão Financeira Global</h1>
                <p className="text-muted-foreground">Resumo financeiro de toda a plataforma</p>
            </div>

            {/* Main Stats */}
            <div className="grid gap-4 md:grid-cols-3">
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Receita Total</CardTitle>
                        <TrendingUp className="h-4 w-4 text-green-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-green-500">
                            {formatCurrency(totalIncome)}
                        </div>
                        <p className="text-xs text-muted-foreground">
                            {formatCurrency(incomeThisMonth)} este mês
                        </p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Despesas Totais</CardTitle>
                        <TrendingDown className="h-4 w-4 text-red-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-red-500">
                            {formatCurrency(totalExpenses)}
                        </div>
                        <p className="text-xs text-muted-foreground">
                            {formatCurrency(expensesThisMonth)} este mês
                        </p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Balanço Líquido</CardTitle>
                        <DollarSign className={`h-4 w-4 ${netBalance >= 0 ? 'text-green-500' : 'text-red-500'}`} />
                    </CardHeader>
                    <CardContent>
                        <div className={`text-2xl font-bold ${netBalance >= 0 ? 'text-green-500' : 'text-red-500'}`}>
                            {formatCurrency(netBalance)}
                        </div>
                    </CardContent>
                </Card>
            </div>

            {/* Secondary Stats */}
            <div className="grid gap-4 md:grid-cols-3">
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Contas Bancárias</CardTitle>
                        <CreditCard className="h-4 w-4 text-blue-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{accountsData.length}</div>
                        <p className="text-xs text-muted-foreground">contas cadastradas</p>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Saldo Total em Contas</CardTitle>
                        <Wallet className="h-4 w-4 text-purple-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">
                            {formatCurrency(totalAccountBalance)}
                        </div>
                    </CardContent>
                </Card>

                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Transações</CardTitle>
                        <PiggyBank className="h-4 w-4 text-orange-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{transactionsData.length}</div>
                        <p className="text-xs text-muted-foreground">registros totais</p>
                    </CardContent>
                </Card>
            </div>

            {/* Accounts List */}
            {accountsData.length > 0 && (
                <Card>
                    <CardHeader>
                        <CardTitle>Contas Bancárias</CardTitle>
                        <CardDescription>Lista de todas as contas cadastradas</CardDescription>
                    </CardHeader>
                    <CardContent>
                        <div className="space-y-3">
                            {accountsData.map((account: any) => (
                                <div key={account.id} className="flex items-center justify-between p-3 border rounded-lg">
                                    <span className="font-medium">{account.name}</span>
                                    <span className={`font-bold ${(account.balance || 0) >= 0 ? 'text-green-500' : 'text-red-500'}`}>
                                        {formatCurrency(account.balance || 0)}
                                    </span>
                                </div>
                            ))}
                        </div>
                    </CardContent>
                </Card>
            )}
        </div>
    );
}
